class Solution {
    public int[] earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        int earliest = Integer.MAX_VALUE, latest = 0;
        for (int round = 1; round <= n; round++) {
            int[] players = new int[n];
            for (int i = 0; i < n; i++) {
                players[i] = i + 1;
            }
            for (int i = 0; i < round; i++) {
                int[] nextRound = new int[(n + 1) / 2];
                int j = 0;
                for (int k = 0; k < n / 2; k++) {
                    if (players[k] == firstPlayer && players[n - k - 1] == secondPlayer) {
                        nextRound[j++] = firstPlayer;
                    } else if (players[k] == secondPlayer && players[n - k - 1] == firstPlayer) {
                        nextRound[j++] = secondPlayer;
                    } else if (players[k] == firstPlayer) {
                        nextRound[j++] = firstPlayer;
                    } else if (players[k] == secondPlayer) {
                        nextRound[j++] = secondPlayer;
                    } else {
                        nextRound[j++] = players[k];
                    }
                }
                if (n % 2 == 1) {
                    nextRound[(n + 1) / 2 - 1] = players[n / 2];
                }
                n = (n + 1) / 2;
                players = nextRound;
            }
            if (players[0] == firstPlayer && players[1] == secondPlayer || players[0] == secondPlayer && players[1] == firstPlayer) {
                earliest = Math.min(earliest, round);
                latest = Math.max(latest, round);
            }
        }
        return new int[] {earliest, latest};
    }
}
